where.if:
AND EXISTS (
  SELECT 1
  FROM weapon_generations generation_filter
  WHERE generation_filter.weapon_id = weapons.id
    AND generation_filter.generation = #{generation}
)

mapper.select:
SELECT
FROM weapons
ORDER BY sort_order ASC, name ASC, id ASC LIMIT #{limit} OFFSET #{offset}

SELECT FROM weapon_generations WHERE weapon_id IN
#{id}
ORDER BY weapon_id ASC, generation ASC

SELECT FROM weapon_slots WHERE weapon_id IN
#{id}
ORDER BY weapon_id ASC, sort_order ASC, slot ASC

SELECT COUNT(*)
FROM build_items item
INNER JOIN builds build ON build.id = item.build_id
WHERE build.weapon_id = #{weaponId}
  AND item.slot IN

    #{slot}

SELECT COUNT(*)
FROM attachment_weapons binding
INNER JOIN attachments attachment ON attachment.id = binding.attachment_id
WHERE binding.weapon_id = #{weaponId}
  AND attachment.slot IN

    #{slot}

SELECT COUNT(*)
FROM builds
WHERE weapon_id = #{weaponId}
  AND generation IN

    #{generation}

SELECT COUNT(*)
FROM attachment_weapons binding
WHERE binding.weapon_id = #{weaponId}
  AND NOT EXISTS (
    SELECT 1
    FROM attachment_generations generation
    WHERE generation.attachment_id = binding.attachment_id
      AND generation.generation IN

